import{_ as t,o as s,c as e,a4 as n}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"语法填空套路","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Review-Routine-006-语法填空套路-V1.0-20260405.md","filePath":"english/Eng-Review-Routine-006-语法填空套路-V1.0-20260405.md"}'),i={name:"english/Eng-Review-Routine-006-语法填空套路-V1.0-20260405.md"};function l(o,a,r,p,h,d){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="语法填空套路" tabindex="-1">语法填空套路 <a class="header-anchor" href="#语法填空套路" aria-label="Permalink to &quot;语法填空套路&quot;">​</a></h1><p><strong>判断词性→确定形式→验证答案</strong></p><hr><h2 id="一、题型特点" tabindex="-1">一、题型特点 <a class="header-anchor" href="#一、题型特点" aria-label="Permalink to &quot;一、题型特点&quot;">​</a></h2><h3 id="命题形式" tabindex="-1">命题形式 <a class="header-anchor" href="#命题形式" aria-label="Permalink to &quot;命题形式&quot;">​</a></h3><ul><li>一篇短文，10个空格</li><li>有提示词（6-7个）：括号内给出单词</li><li>无提示词（3-4个）：纯空格</li></ul><hr><h2 id="二、有提示词-6-7个" tabindex="-1">二、有提示词（6-7个） <a class="header-anchor" href="#二、有提示词-6-7个" aria-label="Permalink to &quot;二、有提示词（6-7个）&quot;">​</a></h2><h3 id="_2-1-动词-⭐-最常考" tabindex="-1">2.1 动词 ⭐（最常考） <a class="header-anchor" href="#_2-1-动词-⭐-最常考" aria-label="Permalink to &quot;2.1 动词 ⭐（最常考）&quot;">​</a></h3><p><strong>Step 1：判断是谓语还是非谓语</strong></p><p><strong>谓语动词</strong>（作句子谓语）：</p><ul><li>考虑：<strong>时态、语态、主谓一致</strong></li></ul><p><strong>非谓语动词</strong>（不作谓语）：</p><ul><li>考虑：<strong>to do / doing / done</strong></li></ul><p><strong>判断方法</strong>：</p><ul><li>句中已有谓语 → 用非谓语</li><li>句中无谓语 → 用谓语</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>He _____ (go) to school every day. （谓语，一般现在时）→ goes</span></span>
<span class="line"><span>He enjoys _____ (read) books. （非谓语，enjoy后接doing）→ reading</span></span>
<span class="line"><span>The book _____ (write) by Lu Xun is famous. （非谓语，被动）→ written</span></span></code></pre></div><h3 id="_2-2-名词" tabindex="-1">2.2 名词 <a class="header-anchor" href="#_2-2-名词" aria-label="Permalink to &quot;2.2 名词&quot;">​</a></h3><p><strong>考点</strong>：</p><ul><li><strong>单复数</strong>：根据谓语动词或限定词判断</li><li><strong>所有格</strong>：&#39;s / of</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>There are many _____ (student) in the classroom. → students</span></span>
<span class="line"><span>This is _____ (Tom) book. → Tom&#39;s</span></span></code></pre></div><h3 id="_2-3-形容词-副词" tabindex="-1">2.3 形容词/副词 <a class="header-anchor" href="#_2-3-形容词-副词" aria-label="Permalink to &quot;2.3 形容词/副词&quot;">​</a></h3><p><strong>考点</strong>：</p><ul><li><strong>词性转换</strong>：形容词↔副词</li><li><strong>比较级/最高级</strong>：根据than或the判断</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>He runs very _____ (quick). → quickly（副词修饰动词）</span></span>
<span class="line"><span>He is _____ (tall) than me. → taller（比较级）</span></span></code></pre></div><h3 id="_2-4-代词" tabindex="-1">2.4 代词 <a class="header-anchor" href="#_2-4-代词" aria-label="Permalink to &quot;2.4 代词&quot;">​</a></h3><p><strong>考点</strong>：</p><ul><li><strong>人称代词</strong>：主格↔宾格</li><li><strong>物主代词</strong>：形容词性↔名词性</li><li><strong>反身代词</strong>：oneself</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Please give _____ (I) a book. → me（宾格）</span></span>
<span class="line"><span>This book is _____ (I). → mine（名词性物主代词）</span></span>
<span class="line"><span>He taught _____ (he) English. → himself（反身代词）</span></span></code></pre></div><h3 id="_2-5-数词" tabindex="-1">2.5 数词 <a class="header-anchor" href="#_2-5-数词" aria-label="Permalink to &quot;2.5 数词&quot;">​</a></h3><p><strong>考点</strong>：</p><ul><li><strong>基数词变序数词</strong>：one → first, two → second</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Today is his _____ (twelve) birthday. → twelfth</span></span></code></pre></div><hr><h2 id="三、无提示词-3-4个-⭐" tabindex="-1">三、无提示词（3-4个）⭐ <a class="header-anchor" href="#三、无提示词-3-4个-⭐" aria-label="Permalink to &quot;三、无提示词（3-4个）⭐&quot;">​</a></h2><h3 id="优先考虑顺序" tabindex="-1">优先考虑顺序 <a class="header-anchor" href="#优先考虑顺序" aria-label="Permalink to &quot;优先考虑顺序&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>冠词 → 介词 → 连词 → 代词</span></span></code></pre></div><h3 id="_3-1-冠词-a-an-the" tabindex="-1">3.1 冠词 (a/an/the) <a class="header-anchor" href="#_3-1-冠词-a-an-the" aria-label="Permalink to &quot;3.1 冠词 (a/an/the)&quot;">​</a></h3><p><strong>用a/an</strong>：</p><ul><li>可数名词单数首次出现</li><li>表示&quot;一个&quot;</li></ul><p><strong>用the</strong>：</p><ul><li>特指（上文提到过）</li><li>唯一事物（the sun, the earth）</li><li>最高级前</li><li>序数词前</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I have _____ book. The book is interesting.</span></span>
<span class="line"><span> → 第一空无提示，用a；第二空特指，用the</span></span></code></pre></div><h3 id="_3-2-介词" tabindex="-1">3.2 介词 <a class="header-anchor" href="#_3-2-介词" aria-label="Permalink to &quot;3.2 介词&quot;">​</a></h3><p><strong>常见考点</strong>：</p><ul><li>固定搭配：in/on/at, for/of/with</li><li>时间介词：in 2024, on Monday, at 3 o&#39;clock</li><li>地点介词：in Beijing, on the street, at school</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am interested _____ English. → in（固定搭配）</span></span>
<span class="line"><span>I was born _____ 2008. → in</span></span></code></pre></div><h3 id="_3-3-连词" tabindex="-1">3.3 连词 <a class="header-anchor" href="#_3-3-连词" aria-label="Permalink to &quot;3.3 连词&quot;">​</a></h3><p><strong>并列连词</strong>：and, but, or, so <strong>从属连词</strong>：</p><ul><li>定语从句：which, that, who, whom, whose, where, when</li><li>名词性从句：what, that, whether, if</li><li>状语从句：because, when, if, although</li></ul><p><strong>例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>This is the book _____ I bought yesterday. → that/which（定语从句）</span></span>
<span class="line"><span>I don&#39;t know _____ he will come. → if/whether（宾语从句）</span></span></code></pre></div><h3 id="_3-4-代词" tabindex="-1">3.4 代词 <a class="header-anchor" href="#_3-4-代词" aria-label="Permalink to &quot;3.4 代词&quot;">​</a></h3><p><strong>it的用法</strong>：</p><ul><li>形式主语：It is important to study hard.</li><li>形式宾语：I find it difficult to learn English.</li></ul><p><strong>关系代词</strong>：which, that, who等（见连词部分）</p><hr><h2 id="四、解题步骤" tabindex="-1">四、解题步骤 <a class="header-anchor" href="#四、解题步骤" aria-label="Permalink to &quot;四、解题步骤&quot;">​</a></h2><h3 id="标准流程" tabindex="-1">标准流程 <a class="header-anchor" href="#标准流程" aria-label="Permalink to &quot;标准流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 通读全文 → 了解大意</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 逐空分析：</span></span>
<span class="line"><span>   有提示词 → 判断词性 → 确定形式</span></span>
<span class="line"><span>   无提示词 → 考虑：冠/介/连/代</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 复读检查：</span></span>
<span class="line"><span>   - 语法是否正确</span></span>
<span class="line"><span>   - 上下文是否通顺</span></span>
<span class="line"><span>   - 拼写是否正确</span></span></code></pre></div><hr><h2 id="五、高频考点总结" tabindex="-1">五、高频考点总结 <a class="header-anchor" href="#五、高频考点总结" aria-label="Permalink to &quot;五、高频考点总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">提示词</th><th style="text-align:center;">考点</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>动词</strong></td><td style="text-align:center;">时态/语态/非谓语</td><td style="text-align:left;">go → went/wenting/gone</td></tr><tr><td style="text-align:center;"><strong>名词</strong></td><td style="text-align:center;">单复数/所有格</td><td style="text-align:left;">student → students/Tom&#39;s</td></tr><tr><td style="text-align:center;"><strong>形容词</strong></td><td style="text-align:center;">变副词/比较级</td><td style="text-align:left;">quick → quickly/quicker</td></tr><tr><td style="text-align:center;"><strong>代词</strong></td><td style="text-align:center;">人称/物主/反身</td><td style="text-align:left;">I → me/mine/myself</td></tr><tr><td style="text-align:center;"><strong>数词</strong></td><td style="text-align:center;">基数变序数</td><td style="text-align:left;">twelve → twelfth</td></tr><tr><td style="text-align:center;"><strong>无提示</strong></td><td style="text-align:center;">冠/介/连/代</td><td style="text-align:left;">a/an/the, in/on, and/but, which/that</td></tr></tbody></table><hr><h2 id="六、检查清单" tabindex="-1">六、检查清单 <a class="header-anchor" href="#六、检查清单" aria-label="Permalink to &quot;六、检查清单&quot;">​</a></h2><ul><li>[ ] 动词：是谓语还是非谓语？时态语态对吗？</li><li>[ ] 名词：单复数对吗？需要所有格吗？</li><li>[ ] 形容词/副词：需要转换吗？需要比较级吗？</li><li>[ ] 无提示词：先想冠词，再想介词，再想连词</li></ul><hr><p><strong>文档编号</strong>: Eng-Review-Routine-006<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,75)])])}const u=t(i,[["render",l]]);export{c as __pageData,u as default};
